                    emit(node.startOffset, "Single space expected between colon and return type", true)
                    if (autoCorrect) {
                        node.upsertWhitespaceAfterMe(" ")
                    }
                }
            }
    }

    private fun exceedsMaxLineLength(colonNode: ASTNode): Boolean {
        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
            return false
        }
        val typeReference =
            colonNode
                .treeParent
                .findChildByType(TYPE_REFERENCE)
                ?: return false
        // Calculate the length if everything would be on one line:
        // column of colon + ": " + return type text
        // Note: 'column' is 1-based and points to the colon position
        val singleLineLength = colonNode.column + 1 + typeReference.textLength
        return singleLineLength > maxLineLength
    }
