        if (maxLineLength == MAX_LINE_LENGTH_PROPERTY_OFF) {
            return false
        }
        val typeReference =
            colonNode
                .treeParent
                .findChildByType(TYPE_REFERENCE)
                ?: return false
        // Calculate the length if everything would be on one line.
        // When the newline between the colon and return type is replaced with a space,
        // everything after the return type (until the next newline) also moves to the same line.
        //
        // Line length = characters before colon + colon (1) + space (1) + rest of line until newline
        // colonNode.column gives us the 1-based column position of the colon (= chars before colon + 1)
        val lengthBeforeColon = colonNode.column - 1
        val lengthAfterColonOnSameLine = 1 + lengthOfRestOfLineAfterColon(typeReference)
        val singleLineLength = lengthBeforeColon + 1 + lengthAfterColonOnSameLine
        return singleLineLength > maxLineLength
    }

    private fun lengthOfRestOfLineAfterColon(typeReference: ASTNode): Int {
        // Find the text from the return type to the next newline (or end of function signature)
        var length = 0
        var node: ASTNode? = typeReference
        while (node != null) {
            if (node.elementType == WHITE_SPACE && node.textContains('\n')) {
                // Found a newline, stop here
                break
            }
            length += node.textLength
            node = node.nextLeaf()
        }
        return length
    }
}"}

