171→internal class RangeTree(seq: List<Int> = emptyList()) {
172→    private var emptyArrayView = ArrayView(0, 0)
173→    private var arr: IntArray = seq.toIntArray()
174→
175→    init {
176→        if (arr.isNotEmpty()) {
177→            arr.reduce { p, n -> require(p <= n) { "Input must be sorted" }; n }
178→        }
179→    }
180→
181→    // runtime: O(log(n)+k), where k is number of matching points
182→    // space: O(1)
183→    fun query(
184→        vmin: Int,
185→        vmax: Int,
186→    ): ArrayView {
187→        var r = arr.size - 1
188→        if (r == -1 || vmax < arr[0] || arr[r] < vmin) {
189→            return emptyArrayView
190→        }
191→        // binary search for min(arr[l] >= vmin)
192→        var l = 0
193→        while (l < r) {
194→            val m = (r + l) / 2
195→            if (vmax < arr[m]) {
196→                r = m - 1
197→            } else if (arr[m] < vmin) {
198→                l = m + 1
199→            } else {
200→                // arr[l] ?<=? vmin <= arr[m] <= vmax ?<=? arr[r]
201→                if (vmin <= arr[l]) break else l++ // optimization
202→                r = m
203→            }
204→        }
205→        if (l > r || arr[l] < vmin) {
206→            return emptyArrayView
207→        }
208→        // find max(k) such as arr[k] < vmax
209→        var k = l
210→        while (k < arr.size) {
211→            if (arr[k] >= vmax) {
212→                break
213→            }
214→            k++
215→        }
216→        return ArrayView(l, k)
217→    }
218→
219→    fun isEmpty(): Boolean = arr.isEmpty()
220→
221→    inner class ArrayView(private var l: Int, private val r: Int) {
222→        val size: Int = r - l
223→
224→        fun get(i: Int): Int {
225→            if (i < 0 || i >= size) {
226→                throw IndexOutOfBoundsException()
227→            }
228→            return arr[l + i]
229→        }
230→
231→        inline fun forEach(cb: (v: Int) -> Unit) {
232→            var i = 0
233→            while (i < size) {
234→                cb(get(i++))
235→            }
236→        }
237→
238→        override fun toString(): String {
239→            if (l == r) {
240→                return "[]"
241→            }
242→            val sb = StringBuilder("[")
243→            var i = l
244→            while (i < r) {
245→                sb.append(arr[i]).append(", ")
246→                i++
247→            }
248→            sb.replace(sb.length - 2, sb.length, "")
249→            sb.append("]")
250→            return sb.toString()
251→        }
252→    }
253→}
